public void initFromAgreementLine(AgreementLine _line)
{
    next initFromAgreementLine(_line);

    this.ETG_IsGrossWeight          = _line.ETG_IsGrossWeight;
    this.ETG_ItemAlternativeName    = _line.ETG_ItemAlternativeName;
    this.ETG_ItemQuantityGroup      = _line.ETG_ItemQuantityGroup;
    this.ETG_OverDeliveryPct        = _line.ETG_OverDeliveryPct;
    this.ETG_PriceType              = _line.ETG_PriceType;
    this.ETG_UnderDeliveryPct       = _line.ETG_UnderDeliveryPct;  



}

public void insert()
{
    ETGAgrrementQualitySpecsLine               agreementQualitySpecsLineHisSrc;
    ETGAgrrementQualitySpecsLineHistory        agreementQualitySpecsLineHisDes;
    ETG_AgreementLineQualityGrpHistory         agreementLineQualityGrpHisDes;
    ETG_AgreementLineQualityGrp                agreementLineQualityGrpHisSrc;

    next insert();

    while select GroupId from agreementLineQualityGrpHisSrc
        where agreementLineQualityGrpHisSrc.AgreementLine == this.AgreementLine
    {
        agreementLineQualityGrpHisDes.AgreementLine   = this.RecId;
        agreementLineQualityGrpHisDes.GroupId         = agreementLineQualityGrpHisSrc.GroupId;
        agreementLineQualityGrpHisDes.insert();
    }
    while select  * from agreementQualitySpecsLineHisSrc
        where agreementQualitySpecsLineHisSrc.AgreementLineRefrecid == this.AgreementLine
    {
        agreementQualitySpecsLineHisDes.MinRange       = agreementQualitySpecsLineHisSrc.MinRange;
        agreementQualitySpecsLineHisDes.MaxRange       = agreementQualitySpecsLineHisSrc.MaxRange;
        agreementQualitySpecsLineHisDes.AdjustmentType = agreementQualitySpecsLineHisSrc.AdjustmentType;
        agreementQualitySpecsLineHisDes.Increment      = agreementQualitySpecsLineHisSrc.Increment;
        agreementQualitySpecsLineHisDes.FixedValue     = agreementQualitySpecsLineHisSrc.FixedValue;
        agreementQualitySpecsLineHisDes.SubGroupId     = agreementQualitySpecsLineHisSrc.SubGroupId;
        agreementQualitySpecsLineHisDes.AgreementLineRefrecid = this.RecId;
        agreementQualitySpecsLineHisDes.GroupID               = agreementQualitySpecsLineHisSrc.GroupID;
        agreementQualitySpecsLineHisDes.GroupDescription      = agreementQualitySpecsLineHisSrc.GroupDescription;
        agreementQualitySpecsLineHisDes.SubGrpId              = agreementQualitySpecsLineHisSrc.SubGrpId;
        agreementQualitySpecsLineHisDes.SubGroupDescription   = agreementQualitySpecsLineHisSrc.SubGroupDescription;
        agreementQualitySpecsLineHisDes.insert();
    }
}

/// <summary>
///
