/// <param name="e"></param>
[DataEventHandler(tableStr(AgreementLineHistory), DataEventType::Updating)]
public static void AgreementLineHistory_onUpdating(Common sender, DataEventArgs e)
{

  //  ETG_PurchaseAgreementLine       eTG_PurchaseAgreementLine;
    AgreementLine               agreementLine;
    AgreementLineHistory      agreementLineHistory = sender;

    select * from agreementLine where agreementLine.RecId == agreementLineHistory.RecId;

    if (agreementLine.RecId)
    {
        agreementLineHistory.ETG_IsGrossWeight          = agreementLine.ETG_IsGrossWeight;
        agreementLineHistory.ETG_ItemAlternativeName    = agreementLine.ETG_ItemAlternativeName;
        agreementLineHistory.ETG_ItemQuantityGroup      = agreementLine.ETG_ItemQuantityGroup;
        agreementLineHistory.ETG_OverDeliveryPct        = agreementLine.ETG_OverDeliveryPct;
        agreementLineHistory.ETG_PriceType              = agreementLine.ETG_PriceType;
        agreementLineHistory.ETG_UnderDeliveryPct       = agreementLine.ETG_UnderDeliveryPct;
    }
  //  agreementLineHistory.doUpdate();

}
